ll extgcd(ll a, ll b, ll& x, ll& y)

{

    ll d = a;

    if (b != 0) {

        d = extgcd(b, a % b, y, x);

        y -= (a / b) * x;

    }

    else {

        x = 1; y = 0;

    }

    return d;

}



ll mod_inverse(ll a, ll m)

{

    ll x, y;

    extgcd(a, m, x, y);

    return (m + x % m) % m;

}



ll mod_fact(ll n, ll p, ll& e)

{

    e = 0;

    if (n == 0)

        return 1;



    ll res = mod_fact(n / p, p, e);

    e += n/p;

    if (n / p % 2 != 0)

        return res * (p - fact[n % p]) % p;



    return res * fact[n % p] % p;

}



ll mod_comb(ll n, ll k, ll p)

{

    if (n < 0 || k < 0 || n < k)

        return 0;



    ll e1, e2, e3;

    ll a1 = mod_fact(n, p, e1), a2 = mod_fact(k, p, e2), a3 = mod_fact(n - k, p, e3);

    if (e1 > e2 + e3)

        return 0;



    return a1 * mod_inverse(a2 * a3 % p, p) % p;

}



void init(ll M)

{

    fact[0] = 1;

    for(ll i = 0; i < MAX; i++){

        fact[i + 1] = fact[i] * (i + 1) % M;

    }

}



ll mod(ll x, ll M)

{

    if (x < 0)

        x += M;



    return x % M;

}



